import{_ as o,o as d,c as t,a3 as c}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"审计日志","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/audit-log.md","filePath":"cosmos/basic-app/audit-log.md","lastUpdated":1783300196000}'),i={name:"cosmos/basic-app/audit-log.md"};function s(a,e,r,n,l,g){return d(),t("div",null,[...e[0]||(e[0]=[c('<h1 id="审计日志" tabindex="-1">审计日志 <a class="header-anchor" href="#审计日志" aria-label="Permalink to &quot;审计日志&quot;">​</a></h1><p>XiHan.BasicApp 把&quot;谁在什么时候、从哪里、对什么做了什么、结果如何&quot;拆成<strong>六类互相独立的日志</strong>，各有专属实体、专属写入通道、专属查询接口与前端页面。它们通过一个共同的 <code>TraceId</code> 串联同一次请求的完整生命周期，从而既能各自聚焦（安全审计 / 性能分析 / 数据溯源 / 稳定性排障各取所需），又能跨表拼出一条完整链路。</p><p>日志的<strong>底座</strong>是框架的结构化日志能力（Serilog 双路输出、多租户日志上下文），详见 <a href="./../framework/packages/logging"><code>../framework/packages/logging</code></a>。本页讲的是 BasicApp 在这套底座之上、面向业务与合规的<strong>审计日志纵切</strong>：实体、脱敏、写入机制、查询监控。</p><h2 id="六类日志一览" tabindex="-1">六类日志一览 <a class="header-anchor" href="#六类日志一览" aria-label="Permalink to &quot;六类日志一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日志</th><th>实体</th><th>记录什么</th><th>写入触发</th><th>权限码（查看）</th></tr></thead><tbody><tr><td>访问日志</td><td><code>SysAccessLog</code></td><td>每次 HTTP 资源访问的鉴权/结果决策（含未授权尝试）</td><td>请求日志中间件</td><td><code>saas:access-log:read</code></td></tr><tr><td>API 日志</td><td><code>SysOpenApiLog</code></td><td>开放接口层的完整请求/响应详情（体/头/耗时/签名）</td><td>开放接口中间件</td><td><code>saas:api-log:read</code></td></tr><tr><td>操作日志</td><td><code>SysOperationLog</code></td><td>业务语义的操作轨迹（用户&quot;做了什么&quot;）</td><td>MVC 动作过滤器</td><td><code>saas:operation-log:read</code></td></tr><tr><td>异常日志</td><td><code>SysExceptionLog</code></td><td>运行时异常（堆栈/请求上下文/严重级别）</td><td>异常中间件 + 异常过滤器</td><td><code>saas:exception-log:read</code></td></tr><tr><td>登录日志</td><td><code>SysLoginLog</code></td><td>每次登录/登出/认证审计尝试（成功与失败）</td><td>认证领域事件</td><td><code>saas:login-log:read</code></td></tr><tr><td>实体变更</td><td><code>SysDiffLog</code></td><td>数据库实体的增删改快照（字段级差异）</td><td>SqlSugar ORM 拦截器</td><td><code>saas:diff-log:read</code></td></tr></tbody></table><blockquote><p>注意&quot;API 日志&quot;的真实实体名是 <code>SysOpenApiLog</code>（开放接口日志），不是 <code>SysApiLog</code>。前端菜单叫&quot;开放接口日志&quot;，路由 <code>/log/api</code>。</p></blockquote><p>这六类的定位刻意划分清楚，避免重复与混淆：</p><ul><li><strong>访问日志 vs API 日志</strong>：访问日志覆盖<strong>所有</strong> HTTP 请求，只记决策结果与轻量上下文（<code>ResourceType=&quot;HttpApi&quot;</code>），不落完整请求体；API 日志只针对带<strong>开放接口签名头</strong>（AccessKey / Signature）的调用，落完整请求/响应体与签名校验结果，用于第三方计费与 APM。</li><li><strong>操作日志 vs API 日志</strong>：操作日志关注<strong>业务语义</strong>（&quot;用户导出了报表&quot;），API 日志关注 <strong>HTTP 事实</strong>（<code>POST /api/export</code>）。</li><li><strong>操作日志 vs 实体变更</strong>：操作日志覆盖宽泛的业务动作；实体变更只记<strong>数据库行</strong>的字段级前后快照，是合规级的数据溯源。</li><li><strong>登录日志 vs 操作日志</strong>：认证类动作（登录/登出/令牌刷新/改密/绑定 MFA）由登录日志专门承担，操作日志写入器会<strong>主动跳过</strong>这些动作（见下），不重复记账。</li></ul><p>所有六张表都是<strong>只追加、永不更新</strong>的审计数据，并且都是<strong>按月分表</strong>（<code>Sys_Xxx_Log_{year}{month}{day}</code>，<code>SplitType.Month</code>）。这带来一条硬约束：<strong>查询与清理必须带时间范围</strong>，否则框架会扫描全部月表。业务上不支持删除，按合规保留期 <code>TRUNCATE</code>/<code>DROP</code> 历史月表。</p><h2 id="逐类详解" tabindex="-1">逐类详解 <a class="header-anchor" href="#逐类详解" aria-label="Permalink to &quot;逐类详解&quot;">​</a></h2><h3 id="访问日志-sysaccesslog" tabindex="-1">访问日志 <code>SysAccessLog</code> <a class="header-anchor" href="#访问日志-sysaccesslog" aria-label="Permalink to &quot;访问日志 `SysAccessLog`&quot;">​</a></h3><p>鉴权链路的<strong>审计终点</strong>：每次资源访问的最终决策落一条。核心字段是 <code>AccessResult</code>（枚举 <code>AccessResult</code>）——按响应状态码映射：</p><table tabindex="0"><thead><tr><th>状态码</th><th>AccessResult</th><th>含义</th></tr></thead><tbody><tr><td>&lt; 400</td><td><code>Success</code></td><td>成功</td></tr><tr><td>401</td><td><code>Unauthorized</code></td><td>未授权（未登录/令牌失效）</td></tr><tr><td>403</td><td><code>Forbidden</code></td><td>权限不足</td></tr><tr><td>404</td><td><code>NotFound</code></td><td>资源不存在</td></tr><tr><td>其它 4xx</td><td><code>Failed</code></td><td>失败</td></tr><tr><td>≥ 500</td><td><code>ServerError</code></td><td>服务器错误</td></tr></tbody></table><p><code>Forbidden</code>/<code>Unauthorized</code> 是&quot;为什么我没权限&quot;这类问题的<strong>第一手排查数据</strong>。访问日志刻意<strong>不记完整请求体</strong>（防敏感信息泄露），只在 <code>ExtendData</code> 里保留已脱敏的查询串。记录方 IP/位置/浏览器/OS/设备等客户端信息由框架的 <code>IClientInfoProvider</code> 统一填充。</p><h3 id="api-日志-sysopenapilog" tabindex="-1">API 日志 <code>SysOpenApiLog</code> <a class="header-anchor" href="#api-日志-sysopenapilog" aria-label="Permalink to &quot;API 日志 `SysOpenApiLog`&quot;">​</a></h3><p>开放接口层的逐请求明细，字段最全：<code>RequestParams</code>/<code>RequestBody</code>/<code>ResponseBody</code>（均限长 32000 字符）、<code>RequestSize</code>/<code>ResponseSize</code>、<code>ExecutionTime</code>、<code>IsSignatureValid</code>/<code>SignatureType</code>（签名算法枚举：<code>HmacSha256</code>/<code>HmacSha512</code>/<code>RsaSha256</code>/<code>RsaSha512</code>/<code>Sm2</code>/<code>Md5</code>/<code>None</code>）、<code>ClientId</code>/<code>AppId</code>（第三方接入方）。</p><p>请求头/响应头字段 <code>RequestHeaders</code>/<code>ResponseHeaders</code> 存在于实体，但被 <code>[JsonIgnore]</code>（<code>System.Text.Json</code> 与 <code>Newtonsoft.Json</code> 双打），<strong>禁止 API 回显</strong>——<code>Authorization</code>/<code>Cookie</code>/<code>Set-Cookie</code> 等敏感头即使入库也不外泄。</p><h3 id="操作日志-sysoperationlog" tabindex="-1">操作日志 <code>SysOperationLog</code> <a class="header-anchor" href="#操作日志-sysoperationlog" aria-label="Permalink to &quot;操作日志 `SysOperationLog`&quot;">​</a></h3><p>面向业务行为，写入器（<code>SaasOperationLogWriter</code>）有两处关键决策：</p><ol><li><strong>查询动作不落库</strong>：先按动作名语义识别 <code>OperationType</code>，若判定为 <code>Query</code> 则直接返回，不记操作日志（避免海量读请求灌满表）。</li><li><strong>认证动作让位登录日志</strong>：<code>Auth</code> 控制器下的 <code>Login</code>/<code>Logout</code>/<code>EmailLogin</code>/<code>RefreshToken</code>/<code>Register</code>/<code>SwitchTenant</code> 等动作跳过（这些由登录日志承担）。</li></ol><p><code>OperationType</code> 是共享枚举（<code>OperationType</code>，也用于实体变更），语义识别优先看动作名而非 HTTP 方法（避免 POST 一律记成&quot;新增&quot;）：</p><table tabindex="0"><thead><tr><th>值</th><th>标签</th><th>值</th><th>标签</th></tr></thead><tbody><tr><td><code>Login</code></td><td>登录</td><td><code>Export</code></td><td>导出</td></tr><tr><td><code>Logout</code></td><td>登出</td><td><code>Review</code></td><td>审核</td></tr><tr><td><code>Query</code></td><td>查询</td><td><code>Approve</code></td><td>审批</td></tr><tr><td><code>Create</code></td><td>新增</td><td><code>StartTask</code></td><td>发起任务</td></tr><tr><td><code>Update</code></td><td>修改</td><td><code>Execute</code></td><td>执行命令</td></tr><tr><td><code>Delete</code></td><td>删除</td><td><code>Restore</code></td><td>恢复（软删除还原）</td></tr><tr><td><code>Import</code></td><td>导入</td><td><code>Other</code></td><td>其他</td></tr></tbody></table><p><code>Result</code> 字段（<code>OperationExecuteResult</code>：<code>Success</code>/<code>Failed</code>/<code>PartialSuccess</code>）记该操作最终结果，勿与实体的启用状态混淆。</p><h3 id="异常日志-sysexceptionlog" tabindex="-1">异常日志 <code>SysExceptionLog</code> <a class="header-anchor" href="#异常日志-sysexceptionlog" aria-label="Permalink to &quot;异常日志 `SysExceptionLog`&quot;">​</a></h3><p>集中记录运行时异常，是技术排障与稳定性改进的数据源。除堆栈（<code>ExceptionStackTrace</code>，限长 32000）与请求上下文外，写入器（<code>SaasExceptionLogWriter</code>）还做两件加工：</p><ul><li><strong>异常来源归类</strong> <code>ExceptionSource</code>：按异常类型/堆栈关键字归入&quot;业务异常 / 数据库异常 / Redis 异常 / 第三方接口异常 / 消息队列异常 / 未捕获异常&quot;。</li><li><strong>严重级别</strong> <code>SeverityLevel</code>（1–5）：状态码 ≥ 500 记 5，否则记 3。</li></ul><p>还落有 <code>ThreadId</code>/<code>ProcessId</code>/<code>ServerHostName</code>/<code>EnvironmentName</code>/<code>ApplicationVersion</code> 等运行环境快照，便于生产复现。字段 <code>IsHandled</code>/<code>HandledTime</code>/<code>HandledBy</code>/<code>HandledRemark</code> 支持异常&quot;处理闭环&quot;（谁在何时标记已处理）。</p><h3 id="登录日志-sysloginlog" tabindex="-1">登录日志 <code>SysLoginLog</code> <a class="header-anchor" href="#登录日志-sysloginlog" aria-label="Permalink to &quot;登录日志 `SysLoginLog`&quot;">​</a></h3><p><strong>所有</strong>登录尝试（含失败）都必须记录，不得丢弃——这是账户安全审计与风控的基础。它不由中间件/过滤器写入，而是由<strong>认证领域事件</strong>驱动（详见<a href="#写入机制">写入机制</a>）：</p><ul><li><code>AuthLoginSucceededDomainEvent</code> / <code>AuthLoginFailedDomainEvent</code> / <code>AuthLogoutDomainEvent</code> / <code>AuthSecurityAuditDomainEvent</code></li><li>事件处理器 <code>AuthLoginEventHandler</code> 把它们统一投影为 <code>LoginLogRecord</code> 写入。</li></ul><p><code>LoginResult</code> 枚举既覆盖登录结果（<code>Success</code>/<code>InvalidCredentials</code>/<code>AccountLocked</code>/<code>AccountDisabled</code>/<code>RequiresTwoFactor</code>/<code>TwoFactorFailed</code>/<code>Failed</code>），也覆盖<strong>认证审计事件</strong>（<code>Logout</code>/<code>TokenRefreshed</code>/<code>PasswordChanged</code>/<code>PasswordReset</code>/<code>MfaBound</code>/<code>MfaUnbound</code>）——即令牌刷新、改密、绑定/解绑 MFA 也统一落这张表。<code>IsRiskLogin</code> 由风控规则判定（异地/新设备/深夜登录），登录事件处理器还会顺带做<strong>并发登录检测</strong>并推送安全通知（新设备/其它设备登录提醒）。</p><h3 id="实体变更-sysdifflog-数据溯源" tabindex="-1">实体变更 <code>SysDiffLog</code>（数据溯源） <a class="header-anchor" href="#实体变更-sysdifflog-数据溯源" aria-label="Permalink to &quot;实体变更 `SysDiffLog`（数据溯源）&quot;">​</a></h3><p>数据库实体级的合规审计：<strong>谁在什么时候改了哪张表哪条记录的哪些字段</strong>。核心是三个 JSON 快照字段：</p><ul><li><code>BeforeData</code>：变更前完整快照</li><li><code>AfterData</code>：变更后完整快照</li><li><code>ChangedFields</code>：本次变更涉及的字段名数组</li></ul><p>变更类型区分 <strong>新增 / 修改 / 删除 / 恢复</strong>，复用 <code>OperationType</code> 枚举（<code>Create</code>/<code>Update</code>/<code>Delete</code>/<code>Restore</code>）。关键判定：<strong>软删除</strong>是 <code>IsDeleted</code> 从 false→true 的 <code>Update</code>，框架识别后记为 <code>Delete</code>；软删除<strong>还原</strong>记为 <code>Restore</code>。写入器（<code>SaasEntityDiffLogWriter</code>）还按操作类型自动定级 <code>RiskLevel</code>（<code>AuditRiskLevel</code>：低/中/高/极高/严重）——删除、导出、执行命令定为极高（4），修改/恢复/审核/审批/导入定为高或中，查询定为低。</p><h2 id="自动脱敏" tabindex="-1">自动脱敏 <a class="header-anchor" href="#自动脱敏" aria-label="Permalink to &quot;自动脱敏&quot;">​</a></h2><p>敏感数据在<strong>落库前</strong>、于请求捕获点由框架的 <code>LogSanitizer</code>（<code>XiHan.Framework.Web.Api.Logging.LogSanitizer</code>）统一脱敏——写入器拿到的记录已经是脱敏后的副本，脱敏后的日志与原始请求缓冲区互不影响。脱敏覆盖三种形态：</p><ol><li><strong>JSON 键值对</strong>：<code>&quot;password&quot;:&quot;xxx&quot;</code> → <code>&quot;password&quot;:&quot;***&quot;</code></li><li><strong>表单/查询串键值对</strong>：<code>password=xxx</code> → <code>password=***</code></li><li><strong>证件号</strong>：18 位（含 <code>YYMMDD</code>）或 15 位身份证，保留首尾各 3 位、中间打码</li></ol><p>内置敏感键（大小写不敏感匹配）为固定清单：</p><p><code>password | passwd | pwd | secret | token | credential | authorization | otp | verifycode | verificationcode | twofactorcode | bankcard | cardno | cardnumber | accountno | idcard | identitycard | idnumber</code></p><p>脱敏在这些点位应用：请求日志中间件对查询串与请求体脱敏；MVC 动作过滤器对动作参数与响应结果脱敏。此外，敏感 HTTP 头（<code>Authorization</code>/<code>Cookie</code>/<code>Set-Cookie</code>）在 <code>SysOpenApiLog</code> 上直接 <code>[JsonIgnore]</code> 不回显，形成第二道防线。落库时各写入器还统一按列长裁剪（<code>SaasLogMappingHelper.TrimOrNull</code>），大文本（体/堆栈/头）限长 32000 字符防止日志爆量。</p><blockquote><p>与&quot;部署重建库、前向单一格式、异常态 fail-closed&quot;的全局约定一致：脱敏是<strong>只前向</strong>的——原文一旦被掩码就不再持久化，无法反查。需要原文的场景应走带审计的专门通道，不能依赖日志。</p></blockquote><h2 id="写入机制" tabindex="-1">写入机制 <a class="header-anchor" href="#写入机制" aria-label="Permalink to &quot;写入机制&quot;">​</a></h2><p>写入采用<strong>框架定义接口、BasicApp 提供实现</strong>的分层：框架的日志管道（中间件/过滤器/AOP）负责在正确的时机捕获记录，<code>XiHan.BasicApp.Saas</code> 通过实现框架的 Writer 接口把记录落到自己的 <code>Sys*Log</code> 表。默认框架把这些 Writer 注册为 <code>Null*Writer</code>（空实现），BasicApp 在 <code>AddSaasLogWriters()</code> 里用真实实现<strong>覆盖</strong>：</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IAccessLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasAccessLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IApiLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasApiLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IOperationLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasOperationLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IExceptionLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasExceptionLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ILoginLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasLoginLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IEntityDiffLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasEntityDiffLogWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddScoped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IEntityAuditContextProvider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SaasEntityDiffContextProvider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span></code></pre></div><h3 id="捕获时机-中间件-过滤器-事件-aop" tabindex="-1">捕获时机：中间件 / 过滤器 / 事件 / AOP <a class="header-anchor" href="#捕获时机-中间件-过滤器-事件-aop" aria-label="Permalink to &quot;捕获时机：中间件 / 过滤器 / 事件 / AOP&quot;">​</a></h3><p>不同日志在请求生命周期的不同位置被捕获：</p><table tabindex="0"><thead><tr><th>日志</th><th>捕获方</th><th>类型</th></tr></thead><tbody><tr><td>访问日志</td><td><code>XiHanRequestLoggingMiddleware</code> → <code>IAccessLogPipeline</code></td><td>ASP.NET 中间件</td></tr><tr><td>API 日志</td><td><code>XiHanApiLoggingMiddleware</code> → <code>IApiLogPipeline</code>（仅带签名头的请求）</td><td>ASP.NET 中间件</td></tr><tr><td>操作日志</td><td><code>XiHanActionLoggingFilter</code> → <code>IOperationLogPipeline</code>（跳过 GET/HEAD/OPTIONS）</td><td>MVC 动作过滤器</td></tr><tr><td>异常日志</td><td><code>XiHanExceptionLoggingMiddleware</code> + 异常过滤器 → <code>IExceptionLogPipeline</code></td><td>中间件 + 过滤器</td></tr><tr><td>登录日志</td><td>认证领域事件 → <code>AuthLoginEventHandler</code> → <code>ILoginLogPipeline</code></td><td>领域事件（本地事件总线）</td></tr><tr><td>实体变更</td><td>SqlSugar ORM 拦截器 → <code>IEntityDiffLogWriter</code></td><td>数据层 AOP</td></tr></tbody></table><h3 id="同步-vs-异步" tabindex="-1">同步 vs 异步 <a class="header-anchor" href="#同步-vs-异步" aria-label="Permalink to &quot;同步 vs 异步&quot;">​</a></h3><p>访问 / API / 操作 / 异常 / 登录五类走框架的 <code>Pipeline</code> 抽象，<strong>默认同步</strong>写入（在请求线程内直接 <code>await writer.WriteAsync</code>）；可通过配置节 <code>XiHan:Web:Api:LogQueue</code> 切换为<strong>异步队列</strong>模式：</p><ul><li><code>EnableAccessLogQueue</code> / <code>EnableApiLogQueue</code> / <code>EnableOperationLogQueue</code> / <code>EnableExceptionLogQueue</code> / <code>EnableLoginLogQueue</code>（默认全 <code>false</code> = 同步）</li><li>开启后记录进 <code>System.Threading.Channels</code> 有界队列（<code>QueueCapacity</code> 默认 10000，<code>DropOnFull</code> 默认 <code>false</code> = 背压等待），由后台 <code>BackgroundService</code>（如 <code>AccessLogQueueWorker</code>）<strong>批量</strong>排空写库（<code>BatchSize</code> 默认 100 / <code>BatchDelayMilliseconds</code> 默认 200ms，先到先触发）</li><li><code>IgnoredPathPrefixes</code>（默认 <code>[&quot;/hubs&quot;]</code>）：SignalR 心跳/协商等路径不记日志</li></ul><blockquote><p>这与全局的&quot;后台异步用 <code>IRedisDelayQueue</code> + 后台服务&quot;约定属于<strong>不同机制</strong>：日志队列走进程内 <code>Channel</code>（低延迟、高吞吐、可丢弃/背压），发件箱/导出等跨请求的可靠任务才走 Redis 延迟队列。二者不要混淆。</p></blockquote><p><strong>实体变更</strong>是唯一不走 <code>Pipeline</code> 队列的：SqlSugar AOP 拦截 <code>Insert</code>/<code>Update</code>/<code>Delete</code>，在执行前后查前后快照、算差异字段、构建 <code>EntityDiffLogRecord</code>，然后<strong>即发即弃</strong>调用 <code>IEntityDiffLogWriter</code>。审计上下文（TraceId/UserId/UserName/TenantId）由 <code>SaasEntityDiffContextProvider.CreateBaseRecord()</code> 从请求上下文补全。为避免<strong>递归审计</strong>，该 Provider 的 <code>ShouldAudit</code> 只审计命名空间含 <code>Domain.Entities</code> 的类型，且<strong>显式排除全部日志表自身</strong>（<code>SysAccessLog</code>/<code>SysOpenApiLog</code>/<code>SysDiffLog</code>/<code>SysExceptionLog</code>/<code>SysLoginLog</code>/<code>SysOperationLog</code> 等）。</p><h2 id="查询与监控" tabindex="-1">查询与监控 <a class="header-anchor" href="#查询与监控" aria-label="Permalink to &quot;查询与监控&quot;">​</a></h2><p>六类日志各有一个查询应用服务（<code>*QueryService</code>），经 <code>[DynamicApi]</code> 直接暴露为 REST（无 Controller），统一放在 <code>Application/QueryServices/Logging/</code>。它们只读（查询/详情），遵循 BasicApp 全局约定：</p><ul><li><strong>分页走 POST</strong>：<code>GetXxxLogPageAsync</code> 显式标 <code>[HttpPost]</code>，前端把整个查询对象（含 <code>conditions</code>/<code>filters</code>/<code>sorts</code>）作 body 下发。</li><li><strong>权限门控</strong>：每个方法用 <code>[PermissionAuthorize(SaasPermissionCodes.XxxLog.Read)]</code> 校验查看权限。</li><li><strong>字段级安全（FLS）</strong>：排序与过滤在下推前经 <code>IFieldSecurityService.GuardSortsAsync</code> / <code>GuardFiltersAsync</code> 门控，剔除<strong>不可读或已脱敏</strong>的字段——保证用户不能借排序/过滤旁路脱敏策略。前端选择的多字段排序优先，无有效排序时回退默认按时间倒序（访问日志按 <code>AccessTime</code>、操作日志按 <code>OperationTime</code>、实体变更按 <code>AuditTime</code> 等）。</li><li><strong>分表查询</strong>：查询链路都带 <code>.SplitTable()</code>，配合时间区间条件命中对应月表。</li></ul><p>查询支持的过滤维度按日志类型定制，共性包括：时间区间（<code>Between</code>）、<code>UserId</code>/<code>UserName</code>、<code>TraceId</code>（跨日志串联同一请求）、关键字模糊、执行耗时区间；再叠加各自特有维度（访问结果、操作类型、异常严重级别、登录结果、实体类型/风险等级等）。</p><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><p>六类日志都可导出：每类有一个导出 Provider（<code>AccessLogExportProvider</code> 等，<code>BusinessType</code> 形如 <code>log.access</code>），复用查询服务分页取数，导出权限用对应的 <code>saas:xxx-log:export</code> 权限码。导出与列表遵循<strong>一致的脱敏</strong>策略。</p><h3 id="前端页面" tabindex="-1">前端页面 <a class="header-anchor" href="#前端页面" aria-label="Permalink to &quot;前端页面&quot;">​</a></h3><p>菜单由后端 <code>PageRegistry</code> 单一注册（建菜单即绑权限码），六个页面挂在&quot;日志&quot;分组下：</p><table tabindex="0"><thead><tr><th>菜单</th><th>路由</th><th>组件</th><th>图标</th></tr></thead><tbody><tr><td>访问日志</td><td><code>/log/access</code></td><td><code>log/access/index</code></td><td><code>lucide:globe</code></td></tr><tr><td>开放接口日志</td><td><code>/log/api</code></td><td><code>log/api/index</code></td><td><code>lucide:webhook</code></td></tr><tr><td>操作日志</td><td><code>/log/operation</code></td><td><code>log/operation/index</code></td><td><code>lucide:mouse-pointer-click</code></td></tr><tr><td>登录日志</td><td><code>/log/login</code></td><td><code>log/login/index</code></td><td><code>lucide:log-in</code></td></tr><tr><td>异常日志</td><td><code>/log/exception</code></td><td><code>log/exception/index</code></td><td><code>lucide:triangle-alert</code></td></tr><tr><td>数据变更</td><td><code>/log/diff</code></td><td><code>log/diff/index</code></td><td><code>lucide:file-diff</code></td></tr></tbody></table><p>每页是一个查询表格（时间区间 + 多维过滤 + 多字段排序 + 导出按钮），点行进共享的详情抽屉 <code>_components/LogDetailDrawer.vue</code> 查看完整字段——实体变更页在详情里渲染 <code>BeforeData</code>/<code>AfterData</code>/<code>ChangedFields</code> 的前后对比。导出按钮受 <code>saas:xxx-log:export</code> 权限码控制（无权限不渲染）。</p><h2 id="与框架的关系" tabindex="-1">与框架的关系 <a class="header-anchor" href="#与框架的关系" aria-label="Permalink to &quot;与框架的关系&quot;">​</a></h2><ul><li><strong>结构化日志底座</strong>：Serilog 双路输出、按天/大小滚动、多租户日志上下文（UserId/TenantId/TraceId），见 <a href="./../framework/packages/logging"><code>../framework/packages/logging</code></a>。审计日志是在此之上的、面向合规的<strong>结构化数据表</strong>，而非文本日志文件。</li><li><strong>日志管道与脱敏</strong>：中间件/过滤器/队列/<code>LogSanitizer</code> 由框架 <code>XiHan.Framework.Web.Api.Logging</code> 提供，BasicApp 只提供 Writer 落库实现。</li><li><strong>实体变更拦截</strong>：由框架 <code>XiHan.Framework.Data.Auditing</code> 的 SqlSugar AOP 提供，BasicApp 提供 <code>IEntityDiffLogWriter</code> 与 <code>IEntityAuditContextProvider</code>。</li><li><strong>动态 API / 分页 / FLS</strong>：查询服务遵循 BasicApp 全局约定，分别见 <a href="./../framework/concepts/dynamic-api"><code>../framework/concepts/dynamic-api</code></a> 与本站 <a href="./permissions"><code>./permissions</code></a>（字段级脱敏、数据范围）。</li></ul>',65)])])}const k=o(i,[["render",s]]);export{h as __pageData,k as default};
